var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이걸로 정리된 건가?","JPN":"これで片づいた？","ENG":"Is this the end?","TWN":"都結束了嗎？"},"stage":{"bg":"MIND","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"굉장하군. 너희들 각자가 나이트메어에 필적하는 전투력을 가지고 있다니…….","JPN":"すごいな、お前たち。人間がナイトメアに匹敵する戦闘力を持つなんて……","ENG":"Incredible. You each possess the power of a Knightmare...","TWN":"好厲害，沒想到你們都具備足以媲美Knightmare的戰鬥力……"},"stage":{"bg":"MIND","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그걸…… 설명하자면 말이 길어지는데…….","JPN":"ははは、その辺は……説明するにはちょっと複雑だけど……","ENG":"Hah hah, it's... a long story...","TWN":"哈哈，這個嘛……說來話長……"},"stage":{"bg":"MIND","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"타피르……. 그 정도의 공격을 받고도 아직 움직일 수 있는 건가?","JPN":"タピル……あれだけの攻撃を受けてまだ動けるのか？","ENG":"Tapir... You can still move after taking all that damage?","TWN":"達爾……受到那麼強烈的攻擊卻還能動？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"어……째서…… 나는…… 모두가 만족하는…… 오늘을……","JPN":"どう……して……僕は……\\nみんなが満足する……今日を……","ENG":"Why... do this...? I... just wanted... everyone... have a perfect... day...","TWN":"為……什麼……我明明……想給大家一個……完美的今天……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"내일은…… 더 나빠질 수도 있는데…….","JPN":"明日は……今日より悪くなるかもしれないのに……","ENG":"Tomorrow... may be worse...","TWN":"明天……或許只會更糟……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래, 확실히 오늘보다 나쁜 내일이 기다리고 있을지도 모르지. 하지만 그렇다고 이대로가 괜찮다는 건 아니야.","JPN":"そうだな。確かに今日より悪い明日が待っているかもしれない。\\nだからと言って、そのままでいいはずがない。","ENG":"You're correct. Tomorrow may be worse than today. However, that doesn't mean it should be avoided.","TWN":"沒錯，明天可能會比今天更糟，但這並不表示可以將你的行為合理化。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"어……째서……","JPN":"どう……して……","ENG":"But... why...?","TWN":"為……什麼……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"인간은 더 나은 내일을 바라니까. 그것을 위해서라면 괴로워도 노력하지.","JPN":"人間はより良い明日を望むからさ。そのために、辛くても努力するんだ。","ENG":"Because mankind always looks for a brighter future. They strive to make it better, no matter the hardship.","TWN":"因為人類期待更好的明天，為此就算辛苦也還是努力堅持。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"맞아. 내일이 있으니까 사람은 살아갈 수 있어.","JPN":"そうね。明日があるから人は生きられる。","ENG":"He's right. We keep moving forward because there is a tomorrow.","TWN":"沒錯，就是因為有明天，人們才可以活下去。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"똑같은 매일을 반복하는 것으로는 살아있다고 할 수 없지.","JPN":"同じ毎日を過ごすことを生きているとは言い難いからな。","ENG":"Reliving the same day can't be called living.","TWN":"重複過同一天並不算是活著。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래, 비록 시간이 걸리더라도 인간은 끊임없이 행복을 추구하니까.","JPN":"だから、人間は少しでも良い未来にするため、幸せな明日を求めて生きるんだ。","ENG":"Yes. Humans will continue to seek happiness, even if it takes time.","TWN":"沒錯，不管要花多長的時間，人類都不會放棄追求幸福的。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그래. 역시 가짜 학원제로는 안 되는 거라구.","JPN":"そっか。そうだよね。やっぱり、偽物の学園祭じゃダメだったんだ。","ENG":"Yeah. And having a fake festival just won't do it.","TWN":"說的好！假的學園祭果然還是不行！"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"모두 함께 매일매일 학원제를 준비하는 건 즐거웠지만…… 그건 내일 학원제의 성공을 바랐기 때문에 즐거웠던 거야.","JPN":"学園祭を成功させるために、みんなで色々考えて、準備するのは、\\nすごく楽しかった。でも、それは明日に控えた学園祭の成功を想っていたから。","ENG":"It was fun preparing for it every day... But that's because we all hoped it would lead to a successful festival the next day.","TWN":"雖然我很享受大家每天一起準備學園祭的時間……但那也是因為我期待明天的學園祭可以成功。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"내일이 오지 않는 매일은 즐거웠지만…… 결국, 즐겁지 않은 거라구!!","JPN":"そんな明日が来ない毎日は楽しいけど、楽しくない。","ENG":"It was fun to repeat today without a tomorrow... But it's ultimately no fun at all!!","TWN":"沒有明天的每一天也很快樂……但結果而言還是不快樂的！！"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그러니까…… 두고 봐! 타피르 선배!","JPN":"だからね、タピル先輩。今に見てて！","ENG":"So... Just watch, Tapir!","TWN":"所以…達爾前輩！你等著吧！"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"다음에는 꿈 같은 게 아니라 <color=#ffd34c>진짜</color>로 주인공이 되어 보일 테니까!!","JPN":"今度は夢なんかじゃなくて<color=#ffd34c>本物</color>の主人公になってみせるから！！","ENG":"Next time, I'll be the <color=#ffd34c>true</color> star of the festival! And not in some dream!!","TWN":"下一次不會是在夢境裡，我會在現實生活中成為<color=#ffd34c>真正</color>的主角！！"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양…….","JPN":"ナイエルさん……","ENG":"Naielle...","TWN":"奈爾……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"생각한 대로야. 이 세계가 붕괴하기 시작했어.","JPN":"思ったとおりだ。この世界の構築が崩れ始めたぞ。","ENG":"Just as I thought. This world has started to collapse.","TWN":"如我所料，這個世界開始瓦解。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"이제 곧 각각 원래 세계로 돌아갈 수 있을 거야.","JPN":"まもなくそれぞれ元の世界に戻れるだろう。","ENG":"We'll soon be able to return to our respective worlds.","TWN":"大家應該很快就可以回到各自的世界。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 여기서 작별이라는 거네?","JPN":"じゃあ、ここでお別れということ？","ENG":"Then, is this goodbye?","TWN":"那是說再見的時候囉？"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그렇게 되겠군.","JPN":"そうなるな。","ENG":"I believe so.","TWN":"沒錯。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워, 를르슈. 덕분에 원래 세계로 돌아갈 수 있게 되었어.","JPN":"ありがとう、ルルーシュ。あなたのおかげで元の世界に戻ることができる。","ENG":"Thanks, Lelouch. We're able to go home because of you.","TWN":"謝謝你，魯路修。因為你，我們才能回到原本的世界。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"아니, 이건 모두가 있었기 때문에 가능한 작전이었어. 나이엘, 너도 포함해서 말이지.","JPN":"いいや、これはみんながいたから成し遂げられたことだ。\\nナイエル、お前もな。","ENG":"No, this plan was successful because everyone pulled their weight. And that also includes you, Naielle.","TWN":"別這麼說，是因為各位才能夠作戰成功。當然也包括你，奈爾。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"흥! 이제와서 친한 척 말 걸지 말라구!","JPN":"フン。今になって気安く話かけんな！","ENG":"Hmph! Don't act like you're my friend now!","TWN":"哼！現在才在說這些好聽話！"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"사과드리죠. 아마도 나이엘 나름의 감사 표현일 겁니다.","JPN":"すみません。これでも感謝しているんです。","ENG":"I must apologize on her behalf. But I believe that is Naielle's way of saying thank you.","TWN":"我代替奈爾道歉，這或許是她表達感謝的方式。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"알고 있어. 나름대로 긴 시간을 보낸 동료들이니까.","JPN":"わかってるよ。長い時間過ごした仲間だからな。","ENG":"I know. We have spent a long time together after all.","TWN":"我明白，畢竟我們也算是相處過很長一段時間的夥伴。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"맞아, 몇번이고 똑같은 하루를 보냈으니까.","JPN":"何度も同じ一日を過ごしたんだものね。","ENG":"Yeah. We repeated the same day countless times.","TWN":"沒錯，一起重複過好幾次同一天。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"후후, 그래 모두 잊지 않을게.","JPN":"ふふっ。みんなのこと、忘れないよ。","ENG":"Hah hah, I won't forget you all.","TWN":"呵呵，是啊，我不會忘記你們的。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"유감스럽지만…… 그건 힘들 수도 있어.","JPN":"そうもいかないかもな。","ENG":"I'm sorry to tell you, but... that might be difficult.","TWN":"可惜……這可能沒辦法。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"이곳은 원래 존재해서는 안 되는 공간. 따라서 여기에서 일어났던 일은 모두 없었던 일이 될 가능성이 높아.","JPN":"ここは存在しえない空間。\\nそこで経験したことは無かったことになる可能性が高い。","ENG":"This place shouldn't exist at all. So, there's a high possibility that whatever happened here will be erased, like it never happened.","TWN":"這裡是原本不該存在的空間，在這裡發生過的事很可能會像沒發生過一樣。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"아마…… 다들 이곳에서 있었던 일을 기억할 수 없게 되겠지.","JPN":"ここでの出来事はすべて忘れてしまうだろう。","ENG":"I'm afraid... that no one will be able to remember what happened here.","TWN":"我想……這些事都不會留在我們的記憶裡。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런가…… 그건 좀 아쉬울지도 모르겠네.","JPN":"そっか。それは残念だね。","ENG":"Is that so...? That's a shame.","TWN":"是嗎……那真的有點可惜。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"어쩔 수 없지. 하지만 다시 만날 가능성이 제로라는 뜻은 아니니까 말이야.","JPN":"致し方ない。\\nだけど、また会えない可能性がゼロというわけじゃないさ。","ENG":"A shame, indeed. But that doesn't mean that the chances of our paths crossing again are zero.","TWN":"這也沒辦法，不過我們重逢的可能性也未必是Zero。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇네. 그런 날이 다시 오길 바랄게.","JPN":"そうだね。その時が来ることを祈ってる。","ENG":"Yeah. I'll be looking forward to the day we meet again.","TWN":"是啊，期待那天的到來。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"어? 몸이……","JPN":"あ、身体が……","ENG":"Huh? My body...","TWN":"喔？身體……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_15"},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무래도 저희가 먼저 떠나게 될 것 같군요.","JPN":"どうやら、私たちの方が先に戻されるようです。","ENG":"I guess it's our time to go.","TWN":"看來我們會先走一步。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 모두들 잘……","JPN":"じゃあね。みんな……","ENG":"Then, goodbye everyo–","TWN":"大家保……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"가버렸네.","JPN":"行っちゃったね。","ENG":"They disappeared.","TWN":"她們走了。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是啊。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"있잖아, 를르슈.","JPN":"ねえ、ルルーシュ。","ENG":"Hey, Lelouch?","TWN":"魯路修，我問你。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"왜 그러지?","JPN":"なんだ？","ENG":"Yes?","TWN":"什麼事？"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"그…… 꿈의 세계에서…… 셜리가 나타났던 건…….","JPN":"あの夢の世界でシャーリーだけ、実体化されていたのは……","ENG":"Uh... Seeing Shirley... in the dream world...","TWN":"夏麗……出現……在那個夢的世界裡……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래. 아마도 나의 바람이었겠지. 셜리가 살아있기를 바랐던 나의 바람…….","JPN":"俺の願望だろうな。\\nシャーリーに生きていて欲しいと願った俺の……","ENG":"Yes, that must've been my desire. My desire that she were still alive...","TWN":"這或許是我的希望吧？希望夏麗還活著……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"를르슈…….","JPN":"ルルーシュ……","ENG":"Lelouch...","TWN":"魯路修……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"감상에 젖는 것도 거기까지야. 우리들도 슬슬 원래 세계로 돌아가야 하니까.","JPN":"感傷に浸るのはそこまでだ。\\nどうやら、私たちも元の世界に戻るらしい。","ENG":"Enough of being sentimental. It's almost our time to go home as well.","TWN":"感傷時刻到此為止，我們也差不多該回到原本的世界了。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"……그렇군.","JPN":"ああ……","ENG":"...I see.","TWN":"……是啊。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"를르슈, 한 가지 궁금한 게 있어.","JPN":"ルルーシュ、一つ聞きたいことがある。","ENG":"Lelouch, I have a question for you.","TWN":"魯路修，我想問你一件事。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"너까지 무슨 일이지, C.C.?","JPN":"お前までなんだ、C.C.？","ENG":"Even you, C.C.?","TWN":"連你也有問題嗎，C.C.？"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"이번 사건은 네가 그 공간이 가짜라는 것을 미리 간파했기 때문에 해결할 수 있었어.","JPN":"今回はあの空間が偽りのものだと、お前が看破したから解決することが出来た。","ENG":"We were able to resolve this because you figured out that this world was fake.","TWN":"這次的事件之所以能解決，是因為你先發現那個空間是假的。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"하지만 어떻게 그렇게 쉽게 간파할 수 있었던 거야?","JPN":"どうしてお前には見破ることが出来たんだ？","ENG":"But how were you able to figure it out so easily?","TWN":"但你為什麼可以如此輕易就發現？"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"셜리의 일도 그렇고…… 너에게 있어서도 그 애쉬포드 학원은 꽤나 행복한 공간이었을 텐데?","JPN":"シャーリーのことといい、お前にとっても\\nあのアッシュフォード学園は心地いい空間だったんだろう？","ENG":"Even Shirley was here... And Ashford must have been a happy place for you too, no?","TWN":"還有夏麗也是……對你而言，那個阿什弗德學院應該也是個幸福的空間吧？"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"틀렸어, C.C.","JPN":"間違っているぞ、C.C.。","ENG":"You're wrong, C.C.","TWN":"你錯了，C.C.。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그 세계에는 나나리가 없었어. 그리고 나나리가 없는 세계에서 내가 살아갈 의미 따위 없지.","JPN":"あの世界にはナナリーがいなかった。\\nナナリーのいない世界で、俺が生きる意味などない。","ENG":"That world didn't have Nunnally. And there is no point of me living in a world where she doesn't exist.","TWN":"在那個世界裡沒有娜娜莉，沒有娜娜莉的世界，對我而言等於沒有活下去的意義。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래서…… 저 세계가 거짓이라는 것을 바로 알 수 있었던 거야.","JPN":"だから、あの世界が偽物だとすぐにわかったんだ。","ENG":"That's how... I was able to realize that the world was fake.","TWN":"所以……我才能馬上就發現那個世界是假的。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"후후. 그럴만하네.","JPN":"ふっ。合点がいったよ。","ENG":"Ha ha, makes sense.","TWN":"呵呵，說的也是。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래. 나나리가 안심하고 지낼 수 있는 세계를 만드는 것…….","JPN":"そうさ。ナナリーが安心して暮らせる世界を創ること、","ENG":"Yes. To create a world where she can live in peace...","TWN":"沒錯，創造一個讓娜娜莉能夠安心生活的世界……"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"오직 그것만이 내가 살아가는 목적이니까.","JPN":"それが俺の生きる目的なのだから。","ENG":"That's my sole purpose of living.","TWN":"這是我活著唯一的目的。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};